    // -------- MOBILE: LOAD ON SCROLL --------
    if (atViewPort === "mobile") {
        const observer = new IntersectionObserver(entries => {
            if (entries[0].isIntersecting) {
                if(both == "yes"){
					rudrSwitchTab('tb_1', 'content_1');
