            slideOpen = false;
            intval = setInterval(function () {
                h -= 7;
                mdiv.style.height = h + 'px';
                mdiv.style.overflow = "hidden";

                if (h = initHeight) {
                    mdiv.style.height = initHeight + 'px';
                    window.clearInterval(intval);
                    mdiv.style.overflow = "visible";
                }
            }, 1);
        }
    }

